                        warn!(path = ?path, error = %e, "Failed to parse existing status file");
                    }
                }
            }
        }
    }

    self.workers = workers.clone();

    // Send initial scan complete event
    let _ = event_tx.send(StatusEvent::InitialScanComplete { workers });

    Ok(())
}

