        assert_eq!(
            watcher.get_worker("worker-mod").unwrap().status,
            WorkerStatus::Idle
        );

        // Receive initial scan event
        let _ = watcher.recv_timeout(Duration::from_millis(100));

        // Modify the file to change status to active
        let new_content = r#"{
            "worker_id": "worker-mod",
