    // In production: use RecommendedWatcher (inotify on Linux) for efficiency
    let log_dir_clone = config.log_dir.clone();
    let event_tx_clone = event_tx.clone();

    #[cfg(test)]
    let mut debouncer = {
        // Use RecommendedWatcher (inotify) in tests
        // The serial test attribute and proper cleanup should prevent inotify exhaustion
        new_debouncer_opt::<_, RecommendedWatcher, _>(
            config.debounce_duration,
            None,
            move |result: DebounceEventResult| {
                match result {
                    Ok(events) => {
                        for event in events {
                            if let Err(e) = process_file_event(&event.event, &log_dir_clone, &event_tx_clone) {
                                let _ = event_tx_clone.send(LogWatcherEvent::Error {
                                    message: e.to_string(),
                                });
                            }
                        }
                    }
                    Err(errors) => {
                        for error in errors {
                            warn!("File watcher error: {:?}", error);
                        }
                    }
                }
            },
            RecommendedCache::new(),
            notify::Config::default(),
        )
        .map_err(|e| LogWatcherError::InitError(format!("Failed to create debouncer: {}", e)))?
    };

    #[cfg(not(test))]
    let mut debouncer = {
        new_debouncer_opt::<_, RecommendedWatcher, _>(
            config.debounce_duration,
            None,
            move |result: DebounceEventResult| {
                match result {
                    Ok(events) => {
                        for event in events {
                            if let Err(e) = process_file_event(&event.event, &log_dir_clone, &event_tx_clone) {
                                let _ = event_tx_clone.send(LogWatcherEvent::Error {
                                    message: e.to_string(),
                                });
                            }
                        }
                    }
                    Err(errors) => {
                        for error in errors {
                            warn!("File watcher error: {:?}", error);
                        }
                    }
                }
            },
            RecommendedCache::new(),
            notify::Config::default(),
        )
        .map_err(|e| LogWatcherError::InitError(format!("Failed to create debouncer: {}", e)))?
    };

    debouncer
        .watch(&config.log_dir, RecursiveMode::NonRecursive)
        .map_err(|e| {
            LogWatcherError::InitError(format!("Failed to watch directory {:?}: {}", config.log_dir, e))
        })?;

    // Keep debouncer alive by leaking it (simplified for sync context)
    // In production, this would be properly managed
    std::mem::forget(debouncer);

    Ok((watcher, event_rx))
}

