type DebouncerType = notify_debouncer_full::Debouncer<RecommendedWatcher, RecommendedCache>;

#[cfg(not(test))]
use notify::RecommendedWatcher;
#[cfg(not(test))]
type DebouncerType = notify_debouncer_full::Debouncer<RecommendedWatcher, RecommendedCache>;
